win.highlightAt = (clientX, clientY) => {
    if (!win.CSS || !win.CSS.highlights) return false;

    let range;
    if (doc.caretRangeFromPoint) {
        range = doc.caretRangeFromPoint(clientX, clientY);
    } else if (doc.caretPositionFromPoint) {
        const pos = doc.caretPositionFromPoint(clientX, clientY);
        range = doc.createRange();
        range.setStart(pos.offsetNode, pos.offset);
        range.collapse(true);
    }

    // Rule 1: Prevent interaction with Question Cards
    const targetNode = range?.startContainer;
    const targetElement = targetNode?.nodeType === 3 ? targetNode.parentElement : targetNode;
    if (targetElement?.closest('.miron-portal-container')) {
        win.CSS.highlights.clear();
        return false;
    }

