 534 |                     // 1. BACKWARD SCAN (Find start)
 535 |                     let currentStartNode = startNode;
 536 |                     let currentStartOffset = startOffset;
 537 |                     let finalStartNode = startNode;
 538 |                     let finalStartOffset = 0;
 539 | 
 540 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 541 |                     let lastPuncIndex = -1;
 542 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 543 |                         if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 544 |                     }
 545 | 
 546 |                     if (lastPuncIndex !== -1) {
 547 |                         finalStartOffset = lastPuncIndex + 1;
 548 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 549 |                     } else {
 550 |                         const walker = createWalker(pageBoundary);
 551 |                         walker.currentNode = currentStartNode;
 552 |                         let prevNode = walker.previousNode();
 553 |                         let foundStart = false;
 554 | 
 555 |                         while (prevNode && !foundStart) {
 556 |                             const text = prevNode.textContent;
 557 |                             for (let i = text.length - 1; i >= 0; i--) {
 558 |                                 if (sentenceEndRegex.test(text[i])) {
 559 |                                     finalStartNode = prevNode; finalStartOffset = i + 1;
 560 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 561 |                                     foundStart = true; break;
