 572 |                     let currentEndNode = startNode;
 573 |                     let currentEndOffset = startOffset;
 574 |                     let finalEndNode = startNode;
 575 |                     let finalEndOffset = startNode.textContent.length;
 576 | 
 577 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 578 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
